<?phpnamespace App\Http\Controllers\Admin;use Illuminate\Http\Request;use App\Http\Controllers\Controller;use App\Mail\CuentaActiva;use App\Models\Cliente;use App\Models\TipoArticulo;use Illuminate\Support\Facades\Hash;use GuzzleHttp\Client;use GuzzleHttp\RequestOptions;use Illuminate\Support\Facades\Mail;use Illuminate\Support\Facades\Log;class ClienteController extends Controller{    private $model = Cliente::class;    private $name = 'Cliente';    private $prefixPermission = 'cliente';    public function all(Request $request, $page = 1)    {                        $data = $this->model::query();        // Aplicar la ordenación para poner los registros con 'orden' vacío o nulo al final                // Aplicar los filtros si existen        if (request()->has('filters') && is_array(request()->filters)) {            foreach ($request->filters as $key => $value) {                if ($key == 'oculto' && $value != '') {                    $data->where('oculto', '=', $value);                } else {                    $data->where(function ($query) use ($value) {                        $query->where('razonSocial', 'like', '%' . $value . '%')                              ->orWhere('cuenta', 'like', '%' . $value . '%');                    });                }            }                    }        $results = $data->paginate(30, ['*'], 'page', $page);        $results = $data->paginate(30);        return response()->json([            'values' => $results->items(), // Datos actuales de la página            'count' => $results->total(),  // Total de registros            'current_page' => $results->currentPage(), // Página actual            'per_page' => $results->perPage(), // Número de registros por página            'last_page' => $results->lastPage(), // Última página disponible        ]);            }            public function allTemp()    {        $data = $this->model::withTrashed()->where('temporal',1)->orderBy('id', 'desc');        if (request()->has('filters') && is_array(request()->filters)) {            foreach (request()->filters as $key => $value) {                $data->where($key, 'like', '%' . $value . '%');            }        }        return $data->paginate();    }public function find($id){    // Log básico de entrada    Log::debug('ClienteController@find inicio', [        'id_cliente' => $id,    ]);    // Cliente HTTP para la API externa    $client = new Client([        'verify' => false, // Ignora la verificación del certificado SSL    ]);    $headers = [        'accept'     => 'application/json',        'X-API-KEY'  => '',    ];    $data = null;    try {        // Intentar obtener el cliente desde la API externa        $response = $client->request('GET', 'https://tytsaapi.ddns.net:8443/clientes/' . $id, [            RequestOptions::HEADERS => $headers,            RequestOptions::TIMEOUT => 8, // evita que quede colgado eternamente        ]);        $data = json_decode($response->getBody(), true);        // Buscar datos adicionales en la base local        $item = Cliente::where('cuenta', $id)->first();        if ($item) {            $data['email']     = $item->email;            $data['descuento'] = $item->descuento;        } else {            $data['email']     = null;            $data['descuento'] = null;        }        Log::debug('ClienteController@find API OK', [            'id_cliente' => $id,        ]);    } catch (\Throwable $e) {        Log::error('ClienteController@find error API', [            'id_cliente' => $id,            'message'    => $e->getMessage(),        ]);        // Si la API falla, intentamos armar los datos solo desde la BD local        $item = Cliente::where('cuenta', $id)->first();        if ($item) {            $data = [                'cuenta'                 => $item->cuenta,                'razonSocial'            => $item->razonSocial,                'direccion'              => $item->direccion,                'provincia'              => $item->provincia,                'codigoVendedor'         => $item->codigoVendedor,                'vendedorDescripcion'    => $item->vendedorDescripcion,                'codigoBonificacion'     => $item->codigoBonificacion,                'bonificacionDescripcion'=> $item->bonificacionDescripcion,                'email'                  => $item->email,                'descuento'              => $item->descuento,            ];        } else {            // Ni API ni BD: cliente no existe            return response()->json(['message' => 'Cliente no encontrado'], 404);        }    }    // Buscamos el cliente local para categorías    $cliente = Cliente::where('cuenta', $id)->first();    $categorias = TipoArticulo::where('oculto', '=', 'false')        ->where('principal', '=', 'true')        ->get();    // Si no existe en la BD, evitamos llamar a un método sobre null    $seleccionadas = [];    if ($cliente) {        $seleccionadas = $cliente            ->categoriasPermitidas()            ->pluck('tipo_articulos.id');    }    return response()->json([        'clientes'      => $data,        'categorias'    => $categorias,        'seleccionadas' => $seleccionadas,    ]);}        public function findTemp($id)    {                $item = $this->model::withTrashed()->find($id);        if ($item) {            // $item->permissions = $item->permissions()->pluck('id');            return $item;        }        return response()->json(['message' => $this->name . ' not found'], 404);    }    public function store(Request $request, $id = null)    {        $request->validate([                        'email'         => 'required|string|max:255',        ]);        // store a new item        if ($id && !$request->has('__form-input-copy')) {            $item = $this->model::where('cuenta', $id)->first();        } else {            $item = new $this->model;        }        if($request->descuento == null){            $item->descuento = 0;        }else{            $item->descuento = $request->descuento;        }        if($request->email){            $item->email = $request->email;        }         if ($request->filled('password')) {            $item->password = Hash::make($request->password);        }        if ($request->has('categorias')) {            // Supongamos que $request->categorias es un JSON que contiene un arreglo de objetos            $categoriasData = json_decode($request->categorias, true);            // Extraer solamente los IDs. Por ejemplo: [ {id: 3, name: "HOGAR"}, {id: 5, ...} ]            $ids = array_map(function ($cat) {                return $cat['id'];            }, $categoriasData);                        $item->categoriasPermitidas()->sync($ids);        }                        $item->save();        return $item;    }       public function storeTemp(Request $request, $id = null)    {        // validate the request        $request->validate([                        'email'         => 'required|string|max:255',        ]);        // store a new item        if ($id && !$request->has('__form-input-copy')) {            $item = $this->model::withTrashed()->find($id);        } else {            $item = new $this->model;        }        //dd($request->nombre);        $item->nombre   = $request->nombre;        $item->apellido   = $request->apellido;        $item->direccion   = $request->direccion;        $item->razonSocial   = $request->razonSocial;        $item->cuit   = $request->cuit;        $item->telefono   = $request->telefono;        $item->localidad   = $request->localidad;        $item->cp   = $request->cp;        $item->tiempo   = $request->tiempo;        $item->empresa = $request->empresa;        $item->email = $request->email;        $item->cuenta = $request->email;        $item->activo =1;        $item->estado = 1;        $item->temporal = 1;        $item->deleted_at = null;        $current_time = time();        if($request->tiempo > $current_time){            $item->activo = 1;            $item->deleted_at = null;        }        if($request->has('password')){            $item->password = Hash::make($request->password);        }        //dd($item);        $item->save();        return $item;    }    public function updateApi(){        $client = new Client();        $baseApiUrl = 'https://tytsaapi.ddns.net:8443/clientes?maxCount=100&page='; // Base URL                        $clientesCreados = 0;        $clientesActualizados = 0;            try {                        for ($page = 0; $page <= 8; $page++) {                               $apiUrl = $baseApiUrl . $page;                                  $respuesta = $client->request('GET', $apiUrl, [                    'headers' => [                        'X-Api-Key' => '', // Ajusta según la clave que necesitas usar                    ],                    'verify' => false,                 ]);                    $productos = json_decode($respuesta->getBody(), true);                     foreach ($productos['values'] as $value) {                    $cuenta = $value['cuenta'];                    $razonSocial = $value['razonSocial'];                    $direccion = $value['direccion'];                    $provincia = $value['provincia'];                    $codigoVendedor = $value['codigoVendedor'];                    $vendedorDescripcion = $value['vendedorDescripcion'];                    $codigoBonificacion = $value['codigoBonificacion'];                    $bonificacionDescripcion = $value['bonificacionDescripcion'];                        // Buscar cliente por cuenta                    $cliente = Cliente::where('cuenta', $cuenta)->first(); // Cambié get() a first()                        if ($cliente) {                        // Si el cliente existe, actualiza sus datos                        $cliente->razonSocial = $razonSocial;                        $cliente->direccion = $direccion;                        $cliente->provincia = $provincia;                        $cliente->CustomerCode = $codigoVendedor;                        $cliente->CustomerDescription = $vendedorDescripcion;                        $cliente->codigoBonificacion = $codigoBonificacion;                        $cliente->bonificacionDescripcion = $bonificacionDescripcion;                        $cliente->descuento = $this->parseBonificacion($bonificacionDescripcion);                        $cliente->estado = 1;                        $cliente->save(); // Guarda los cambios                            // Incrementar contador de clientes actualizados                        $clientesActualizados++;                    } else {                        // Si no existe, crea un nuevo cliente                        $cliente = new Cliente();                        $cliente->cuenta = $cuenta; // Asegúrate de que la propiedad username esté presente                        $cliente->razonSocial = $razonSocial;                        $cliente->direccion = $direccion;                        $cliente->provincia = $provincia;                        $cliente->CustomerCode = $codigoVendedor;                        $cliente->CustomerDescription = $vendedorDescripcion;                        $cliente->codigoBonificacion = $codigoBonificacion;                        $cliente->bonificacionDescripcion = $bonificacionDescripcion;                        $cliente->descuento = $this->parseBonificacion($bonificacionDescripcion);                        $cliente->estado = 1;                        $cliente->save(); // Guarda el nuevo cliente                            // Incrementar contador de clientes creados                        $clientesCreados++;                    }                }            }            $client = new Client([                'verify' => false, // Ignora la verificación del certificado SSL            ]);                    $headers = [                'accept' => 'application/json',                'X-API-KEY' => ''            ];                    $allClientData = [];                    // Itera a través de las páginas de la API para traer todos los clientes            for ($i = 1; $i <= 13; $i++) {  // Aquí se establece hasta 13 páginas como ejemplo, ajusta según el total necesario                $response = $client->request('GET', 'https://tytsaapi.ddns.net:8443/clientes?maxCount=100&page=' . $i, [                    RequestOptions::HEADERS => $headers,                ]);                $clientData = json_decode($response->getBody(), true);                if (isset($clientData['values'])) {                    $allClientData = array_merge($allClientData, $clientData['values']);                }            }                    // Filtra los clientes si existen filtros            if (request()->has('filters') && is_array(request()->filters)) {                $filteredData = [];                foreach ($allClientData as $client) {                    $matchesFilter = true;                    foreach (request()->filters as $key => $value) {                        $searchValue = strtolower(mb_convert_encoding($value, 'ASCII', 'UTF-8'));                        $matchesProperty = false;                        foreach ($client as $clientProperty => $clientValue) {                            $clientValue = strtolower(mb_convert_encoding(json_encode($clientValue), 'ASCII', 'UTF-8'));                            if (mb_stripos($clientValue, $searchValue) !== false) {                                $matchesProperty = true;                                break;                            }                        }                        if (!$matchesProperty) {                            $matchesFilter = false;                            break;                        }                    }                    if ($matchesFilter) {                        $filteredData[] = $client;                    }                }                $allClientData = $filteredData;            }                    // Obtiene los clientes de la base de datos y los combina con los clientes de la API            $localClients = Cliente::all()->toArray(); // Ajusta el modelo y consulta según tu estructura            $combinedClients = array_merge($allClientData, $localClients);                    // Elimina posibles duplicados (por ejemplo, por ID único si tienen un campo en común)            $uniqueClients = array_map("unserialize", array_unique(array_map("serialize", $combinedClients)));                    return response()->json(['values' => $uniqueClients]);                 } catch (\Exception $e) {            return response()->json(['error' => 'Error al obtener productos: ' . $e->getMessage()], 500);        }                }    public function delete($id)    {        $item = $this->model::find($id);        $item->delete();        return $item;    }    public function restore($id)    {        $item = $this->model::withTrashed()->find($id);        $item->restore();        return $item;    }    public function destroy($id)    {        $item = $this->model::withTrashed()->find($id);        $item->forceDelete();        return $item;    }    public function listSelect(Request $request)    {        $data = $this->model::orderBy('id', 'desc');        if (request()->has('search') && strlen(request()->search)) {            $data->where(function ($query) {                $keys = ['empresa', 'nombre'];                foreach ($keys as $key => $colName) {                    $query->orWhere($colName, 'like', '%' . request()->search . '%');                }            });        }        if (request()->has('optionKey')) {            $data->where('id', request()->optionKey);        }        return $data->get();    } function parseBonificacion($bonificacionDescripcion) {    // Mapear los descuentos posibles    for ($i = 1; $i <= 30; $i++) {        $bonificaciones[(string)$i] = $i;    }        // Añadir los valores para los casos de 30+5 en adelante    $bonificaciones += [        'SIN' => 0,        '30+5' => 33.5,        '30+10' => 37,        '30+15' => 40.5,        '30+20' => 44,        '30+25' => 47.5,        '30+30' => 51,    ];    // Retornar el valor numérico si existe en el mapa    return $bonificaciones[$bonificacionDescripcion] ?? null; // Retorna null si no coincide}    public function habilitar($id)    {        $user = $this->model::find($id);            if ($user) {            $user->estado = $user->estado == 1 ? 0 : 1;  // Cambia el estado (de 1 a 0 o de 0 a 1)            $user->save();            $email = new CuentaActiva($user, 'Tu usuario sigue con la misma contraseña anterior');            Mail::to('info@tytsa.com.ar')->send($email);            Mail::to('dcamacho.tytsa@gmail.com')->send($email);            Mail::to('lmorales.tytsa@gmail.com')->send($email);            Mail::to('ariel@tytsa.com.ar')->send($email);            Mail::to($user->email)->send($email);                return response()->json(['success' => true, 'estado' => $user->estado]);        }            return response()->json(['success' => false, 'message' => 'Usuario no encontrado.'], 404);    }}